CREATE TABLE products (
  product_id   INT PRIMARY KEY,
  name         VARCHAR(80) NOT NULL,
  price        DECIMAL(8,2),
  category     VARCHAR(40)
);

INSERT INTO products VALUES
  (1, 'Laptop',      999.99, 'Electronics'),
  (2, 'Mouse',        19.99, 'Electronics'),
  (3, 'Notebook',      5.99, 'Stationery');

-- Verify initial structure
SELECT * FROM products;

-- ALTER: Add a stock column with a default value
ALTER TABLE products ADD COLUMN stock INT DEFAULT 0;

-- ALTER: Add a discount_percent column
ALTER TABLE products ADD COLUMN discount_percent DECIMAL(4,1) DEFAULT 0.0;

-- Update stock for existing products
UPDATE products SET stock = 100 WHERE product_id = 1;
UPDATE products SET stock = 500 WHERE product_id = 2;
UPDATE products SET stock = 1000 WHERE product_id = 3;

-- View updated table
SELECT * FROM products;

-- ALTER: Drop a column (if category is no longer needed)
ALTER TABLE products DROP COLUMN category;

SELECT * FROM products;

CREATE TABLE items (
  item_id    INT PRIMARY KEY,
  item_name  VARCHAR(50),
  price      INT,           -- stored as INT, need to change to DECIMAL
  qty        SMALLINT
);

INSERT INTO items VALUES (1,'Laptop',1000,5),(2,'Mouse',20,100),(3,'Monitor',300,20);

SELECT * FROM items;

-- ALTER: Change price from INT to DECIMAL(8,2)
ALTER TABLE items ALTER COLUMN price TYPE DECIMAL(8,2);

-- ALTER: Rename a column
ALTER TABLE items RENAME COLUMN item_name TO product_name;

-- ALTER: Rename qty to quantity
ALTER TABLE items RENAME COLUMN qty TO quantity;

-- View the changes
SELECT * FROM items;

-- ALTER: Rename the table itself
ALTER TABLE items RENAME TO products_v2;

-- Query with the new table name
SELECT product_name, price, quantity FROM products_v2 ORDER BY price DESC;

CREATE TABLE staff (
  staff_id   INT PRIMARY KEY,
  name       VARCHAR(60),
  email      VARCHAR(80),
  salary     DECIMAL(10,2),
  department VARCHAR(40)
);

INSERT INTO staff VALUES
  (1, 'Alice', 'alice@co.com', 85000, 'Engineering'),
  (2, 'Bob',   'bob@co.com',   72000, 'Marketing'),
  (3, 'Carol', 'carol@co.com', 68000, 'HR');

-- Add a UNIQUE constraint on email
ALTER TABLE staff ADD CONSTRAINT uq_staff_email UNIQUE (email);

-- Add a CHECK constraint on salary (must be positive)
ALTER TABLE staff ADD CONSTRAINT chk_salary_positive CHECK (salary > 0);

-- This INSERT would fail UNIQUE constraint
-- INSERT INTO staff VALUES (4, 'Dave', 'alice@co.com', 90000, 'Finance');

-- This INSERT would fail CHECK constraint
-- INSERT INTO staff VALUES (5, 'Eve', 'eve@co.com', -5000, 'Finance');

-- Valid new employee
INSERT INTO staff VALUES (4, 'Dave', 'dave@co.com', 90000, 'Finance');

SELECT * FROM staff ORDER BY staff_id;

-- Drop the CHECK constraint
ALTER TABLE staff DROP CONSTRAINT chk_salary_positive;

-- View remaining constraints
SELECT constraint_name, constraint_type
FROM information_schema.table_constraints
WHERE table_name = 'staff';
